@simulation_bp.route('/track-changes', methods=['POST'])
def track_changes():
    data = request.get_json() or {}

    session_id = data.get('session_id', 'default')
    changes = data.get('changes', {})
    action = data.get('action', 'update')

    if action == 'clear':
        clear_user_changes(session_id)
